from math import isqrt

def is_prime(n: int) -> bool:
    """Return True if n is a prime number, otherwise False.

    Uses trial division up to sqrt(n), skipping even numbers for efficiency.
    """
    if n < 2:
        return False
    if n in (2, 3):
        return True
    if n % 2 == 0:
        return False

    limit = isqrt(n)
    for i in range(3, limit + 1, 2):
        if n % i == 0:
            return False
    return True
